            &#39;__isset&#39;,
            &#39;__unset&#39;,
            &#39;__invoke&#39;,
            &#39;__set_state&#39;    &#x2F;&#x2F; 可以根据题目环境将指定的方法添加进来, 来遍历存在指定方法的原生类
        ))) &#123;
            print $class . &#39;::&#39; . $method . &quot;\n&quot;;
